tags: ["Path_Images"],
text: "Which cells are not present in the layer marked as D?",
options: [{"id": "A", "text": "Keratinocytes", "is_correct": false}, {"id": "B", "text": "Merkel cells", "is_correct": false}, {"id": "C", "text": "Melanocytes", "is_correct": false}, {"id": "D", "text": "Langerhans cells", "is_correct": true}],
